import React from 'react';
import { FormEmbedProvider } from '../form/FormEmbedContext';
import { PhieuThuFormParent } from '../../features/kt/cash-voucher/receipt';
import { PhieuChiFormParent } from '../../features/kt/cash-voucher/payment';
import { JournalEntryForm } from '../kt/JournalEntryForm';
import { JOURNAL_ENTRY_ADJUSTING_CONFIG } from '../../constants/journalEntryPageConfig';
import { PurchaseInvoiceForm } from '../kt/PurchaseInvoiceForm';
import { TamUngFormParent } from '../../features/kt/tam-ung';
import { resolveDocumentViewPath } from '../../utils/reportDocumentDrillDown';
import styles from './ReportSourceDocumentSlideout.module.css';

const DOCUMENT_FORMS: Record<string, React.ReactNode> = {
  CashReceipt: <PhieuThuFormParent />,
  CashPayment: <PhieuChiFormParent />,
  JournalEntry: <JournalEntryForm config={JOURNAL_ENTRY_ADJUSTING_CONFIG} />,
  PurchaseInvoice: (
    <PurchaseInvoiceForm
      title="hóa đơn mua DV"
      voucherCode="HDV"
      listPath="/kt/hdmh-dv"
    />
  ),
  AdvancePayment: <TamUngFormParent />,
};

export type ReportDocumentFormEmbedProps = {
  documentType: string;
  documentId: string;
  testIdPrefix: string;
};

export const ReportDocumentFormEmbed: React.FC<ReportDocumentFormEmbedProps> = ({
  documentType,
  documentId,
  testIdPrefix,
}) => {
  const path = resolveDocumentViewPath(documentType, documentId);
  const form = DOCUMENT_FORMS[documentType];

  if (!path || !form) {
    return (
      <div className={styles.unsupported} data-testid={`${testIdPrefix}-slideout-unsupported`}>
        Không hỗ trợ loại chứng từ này.
      </div>
    );
  }

  return (
    <FormEmbedProvider mode="slideout" documentId={documentId}>
      <div className={styles.formEmbed} data-testid={`${testIdPrefix}-slideout-form-embed`}>
        {form}
      </div>
    </FormEmbedProvider>
  );
};
