import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import type {
  BankStatementImportRow,
  CustomerMatchGroup,
  CustomerResolution,
} from '../../../../../services/kt/bankStatementImportModels';
import { bankStatementImportService } from '../../../../../services/kt/bankStatementImportService';
import { POSTING_CATEGORIES } from '../../../../../services/kt/bankStatementPostingRules';
import styles from './CustomerGroupMatch.module.css';

// ── Types ─────────────────────────────────────────────────────

interface Props {
  rows: BankStatementImportRow[];
  fileName: string;
  onConfirm: (resolutions: CustomerResolution[]) => void;
  onBack: () => void;
}

type MatchPhase = 'matching' | 'reviewing';

interface ClientGroup {
  key: string;
  counterpartyName: string;
  bankAccountCode: string;
  rowIndices: number[];
  representativeRow: BankStatementImportRow;
  postingCategoryCode?: string;
  isExpenseKind: boolean;
}

interface MGroup {
  key: string;
  counterpartyName: string;
  bankAccountCode: string;
  rowIndices: number[];
  rowCount: number;
  isExpenseKind: boolean;
  postingCategoryCode?: string;
  postingCategoryLabel?: string;
  // từ API
  apiGroup?: CustomerMatchGroup;
  // resolution
  selectedId?: string;     // customer id đã chọn
  createNew: boolean;
  newCustomerName?: string;
  postingCode?: string;    // định khoản chi phí user chọn
  skip: boolean;
  showLookup: boolean;
  searchTerm: string;
}

const EXPENSE_CODES = new Set(
  POSTING_CATEGORIES.filter(c => c.kind === 'expense').map(c => c.code),
);

// ── Helpers ───────────────────────────────────────────────────

function groupByCounterparty(rows: BankStatementImportRow[]): ClientGroup[] {
  const map = new Map<string, ClientGroup>();
  for (const row of rows) {
    const name = (row.counterpartyName || '').trim();
    const acct = (row.bankAccountCode || '').trim();
    const key = `${name}|||${acct}`;
    if (!map.has(key)) {
      const catEntry = POSTING_CATEGORIES.find(c => c.code === row.postingCategoryCode);
      map.set(key, {
        key, counterpartyName: name, bankAccountCode: acct,
        rowIndices: [], representativeRow: row,
        postingCategoryCode: row.postingCategoryCode,
        isExpenseKind: catEntry?.kind === 'expense',
      });
    }
    map.get(key)!.rowIndices.push(row.rowIndex);
  }
  return Array.from(map.values());
}

// ── Component ─────────────────────────────────────────────────

const CustomerGroupMatch: React.FC<Props> = ({ rows, fileName, onConfirm, onBack }) => {
  const [phase, setPhase] = useState<MatchPhase>('matching');
  const [progress, setProgress] = useState({ done: 0, total: 0 });
  const [groups, setGroups] = useState<MGroup[]>([]);
  const [filterTab, setFilterTab] = useState<'all' | 'pending' | 'done'>('all');
  const [createModalKey, setCreateModalKey] = useState<string | null>(null);
  const runRef = useRef(false);

  // ── Batch match on mount ──────────────────────────────────
  useEffect(() => {
    if (runRef.current) return;
    runRef.current = true;
    void runBatchMatch();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const runBatchMatch = async () => {
    const clientGroups = groupByCounterparty(rows);
    const BATCH = 100;
    setProgress({ done: 0, total: clientGroups.length });

    const apiGroupMap = new Map<string, CustomerMatchGroup>();

    for (let i = 0; i < clientGroups.length; i += BATCH) {
      const batch = clientGroups.slice(i, i + BATCH);
      const repRows = batch.map(cg => cg.representativeRow);
      try {
        const result = await bankStatementImportService.matchCustomers(repRows, fileName);
        for (const g of result.groups) {
          // Match API group back to clientGroup by representative rowIndex
          const matchedClient = batch.find(cg =>
            cg.rowIndices.includes(g.rowIndices[0] ?? -999),
          );
          if (matchedClient) apiGroupMap.set(matchedClient.key, g);
        }
      } catch { /* ignore batch error — continue with no match */ }
      setProgress({ done: Math.min(i + BATCH, clientGroups.length), total: clientGroups.length });
      await new Promise<void>(r => setTimeout(r, 0));
    }

    const mg: MGroup[] = clientGroups.map(cg => {
      const apiG = apiGroupMap.get(cg.key);
      const catEntry = POSTING_CATEGORIES.find(c => c.code === cg.postingCategoryCode);
      return {
        key: cg.key,
        counterpartyName: cg.counterpartyName,
        bankAccountCode: cg.bankAccountCode,
        rowIndices: cg.rowIndices,
        rowCount: cg.rowIndices.length,
        isExpenseKind: cg.isExpenseKind,
        postingCategoryCode: cg.postingCategoryCode,
        postingCategoryLabel: catEntry?.label,
        apiGroup: apiG,
        selectedId: apiG?.exactMatch?.customerId,
        createNew: false,
        skip: false,
        showLookup: false,
        searchTerm: '',
        postingCode: apiG ? undefined : catEntry?.postingCodes?.[0],
      };
    });

    setGroups(mg);
    setPhase('reviewing');
  };

  // ── Mutate group ──────────────────────────────────────────
  const updateGroup = useCallback((key: string, patch: Partial<MGroup>) => {
    setGroups(prev => prev.map(g => g.key === key ? { ...g, ...patch } : g));
  }, []);

  // ── Resolved check ────────────────────────────────────────
  const pendingGroups = useMemo(() => groups.filter(g => {
    if (g.skip) return false;
    if (g.isExpenseKind) return false;                    // expense → auto-ok
    if (g.selectedId) return false;                       // auto or manual matched
    if (g.createNew) return false;                        // create new confirmed
    return true;                                          // still pending
  }), [groups]);

  // ── Summary ───────────────────────────────────────────────
  const summary = useMemo(() => {
    let autoMatch = 0, needsAction = 0, expense = 0, skip = 0, createNew = 0;
    for (const g of groups) {
      if (g.skip) { skip++; continue; }
      if (g.isExpenseKind) { expense++; continue; }
      if (g.createNew) { createNew++; continue; }
      if (g.apiGroup?.exactMatch) autoMatch++;
      else needsAction++;
    }
    return { autoMatch, needsAction, expense, skip, createNew };
  }, [groups]);

  // ── Filter ────────────────────────────────────────────────
  const filteredGroups = useMemo(() => {
    switch (filterTab) {
      case 'pending': return groups.filter(g =>
        !g.skip && !g.isExpenseKind && !g.selectedId && !g.createNew,
      );
      case 'done': return groups.filter(g =>
        g.skip || g.isExpenseKind || !!g.selectedId || g.createNew,
      );
      default: return groups;
    }
  }, [groups, filterTab]);

  // ── Build resolutions ─────────────────────────────────────
  const handleProceed = useCallback(() => {
    const resolutions: CustomerResolution[] = [];
    for (const g of groups) {
      for (const rowIdx of g.rowIndices) {
        if (g.skip) {
          resolutions.push({ rowIndex: rowIdx, skipOnImport: true });
        } else if (g.createNew) {
          resolutions.push({
            rowIndex: rowIdx,
            newCustomer: {
              name: g.newCustomerName || g.counterpartyName,
              autoGenerateCode: true,
              customerGroupId: '',
            },
          });
        } else if (g.selectedId) {
          resolutions.push({ rowIndex: rowIdx, existingCustomerId: g.selectedId });
        } else {
          resolutions.push({ rowIndex: rowIdx });
        }
      }
    }
    onConfirm(resolutions);
  }, [groups, onConfirm]);

  // ── Matching progress view ────────────────────────────────
  if (phase === 'matching') {
    const pct = progress.total > 0 ? Math.round((progress.done / progress.total) * 100) : 0;
    return (
      <div className={styles.container}>
        <h3 className={styles.title}>Xác nhận đối tượng khách hàng</h3>
        <div className={styles.progressSection}>
          <div className={styles.progressLabel}>
            Đang phân tích {progress.done} / {progress.total} nhóm đối tác...
          </div>
          <div className={styles.progressTrack}>
            <div className={styles.progressFill} style={{ width: `${pct}%` }} />
          </div>
          <div className={styles.progressPct}>{pct}%</div>
        </div>
      </div>
    );
  }

  // ── Summary cards ─────────────────────────────────────────
  const summaryCards = [
    { label: 'Tự động khớp', value: summary.autoMatch, color: '#22c55e' },
    { label: 'Cần xác nhận', value: summary.needsAction, color: '#f59e0b' },
    { label: 'Chi phí', value: summary.expense, color: '#8b5cf6' },
    { label: 'Tạo mới', value: summary.createNew, color: '#3b82f6' },
    { label: 'Bỏ qua', value: summary.skip, color: '#9ca3af' },
  ];

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <h3 className={styles.title}>Xác nhận đối tượng khách hàng</h3>
        <p className={styles.subtitle}>
          Hệ thống đã khớp tự động theo tên và tài khoản NH. Xem lại và chỉnh sửa trước khi tiếp tục.
        </p>
      </div>

      {/* Summary */}
      <div className={styles.summaryCards}>
        {summaryCards.map(c => (
          <div key={c.label} className={styles.card} style={{ borderTopColor: c.color }}>
            <span className={styles.cardValue} style={{ color: c.color }}>{c.value}</span>
            <span className={styles.cardLabel}>{c.label}</span>
          </div>
        ))}
      </div>

      {/* Filter tabs */}
      <div className={styles.filterTabs}>
        {[
          { key: 'all' as const, label: `Tất cả (${groups.length})` },
          { key: 'pending' as const, label: `Chưa xử lý (${pendingGroups.length})` },
          { key: 'done' as const, label: `Đã xử lý (${groups.length - pendingGroups.length})` },
        ].map(t => (
          <button key={t.key}
            className={`${styles.filterTab} ${filterTab === t.key ? styles.filterTabActive : ''}`}
            onClick={() => setFilterTab(t.key)}
          >{t.label}</button>
        ))}
      </div>

      {/* Grid table */}
      <div className={styles.tableWrap}>
        <table className={styles.grid}>
          <thead>
            <tr>
              <th className={styles.th} style={{ width: 36 }}>#</th>
              <th className={styles.th}>Đối tác</th>
              <th className={styles.th} style={{ width: 50, textAlign: 'right' }}>Dòng</th>
              <th className={styles.th} style={{ width: 100 }}>Trạng thái</th>
              <th className={styles.th}>Đối tượng / Định khoản</th>
              <th className={styles.th} style={{ width: 96 }}>Hành động</th>
            </tr>
          </thead>
          <tbody>
            {filteredGroups.map((g, idx) => (
              <GroupRow
                key={g.key}
                idx={filteredGroups.indexOf(g) + 1}
                g={g}
                onUpdate={patch => updateGroup(g.key, patch)}
                onCreateNew={() => setCreateModalKey(g.key)}
              />
            ))}
            {filteredGroups.length === 0 && (
              <tr><td colSpan={6} className={styles.empty}>Không có nhóm nào.</td></tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Actions */}
      <div className={styles.actions}>
        <button className={styles.backBtn} onClick={onBack}>Quay lại</button>
        <button
          className={styles.nextBtn}
          disabled={pendingGroups.length > 0}
          title={pendingGroups.length > 0 ? `Còn ${pendingGroups.length} nhóm chưa xử lý` : undefined}
          onClick={handleProceed}
        >
          {pendingGroups.length > 0 ? `Còn ${pendingGroups.length} nhóm chưa xử lý` : `Tiếp theo →`}
        </button>
      </div>

      {/* Create new modal */}
      {createModalKey && (
        <CreateCustomerModal
          group={groups.find(g => g.key === createModalKey)!}
          onConfirm={(name) => {
            updateGroup(createModalKey, { createNew: true, newCustomerName: name, showLookup: false });
            setCreateModalKey(null);
          }}
          onClose={() => setCreateModalKey(null)}
        />
      )}
    </div>
  );
};

// ── GroupRow ──────────────────────────────────────────────────

interface GroupRowProps {
  idx: number;
  g: MGroup;
  onUpdate: (patch: Partial<MGroup>) => void;
  onCreateNew: () => void;
}

const POSTING_OPTS = POSTING_CATEGORIES.filter(c => c.kind === 'expense').map(c => ({
  code: c.code, label: c.label,
}));

const GroupRow: React.FC<GroupRowProps> = ({ idx, g, onUpdate, onCreateNew }) => {
  const isResolved = g.skip || g.isExpenseKind || !!g.selectedId || g.createNew;

  // Status badge
  let statusBg = '#fef3c7', statusFg = '#92400e', statusText = 'Chưa xử lý';
  if (g.skip) { statusBg = '#f3f4f6'; statusFg = '#6b7280'; statusText = 'Bỏ qua'; }
  else if (g.isExpenseKind) { statusBg = '#ede9fe'; statusFg = '#7c3aed'; statusText = 'Chi phí'; }
  else if (g.createNew) { statusBg = '#dbeafe'; statusFg = '#1d4ed8'; statusText = 'Tạo mới'; }
  else if (g.selectedId) {
    const isAuto = g.apiGroup?.exactMatch?.customerId === g.selectedId;
    statusBg = isAuto ? '#dcfce7' : '#e0f2fe';
    statusFg = isAuto ? '#15803d' : '#0369a1';
    statusText = isAuto ? 'Tự động' : 'Đã chọn';
  }

  // Candidates filtered by searchTerm
  const cands = useMemo(() => {
    const all = g.apiGroup?.candidates ?? [];
    if (!g.searchTerm) return all;
    const t = g.searchTerm.toLowerCase();
    return all.filter(c => c.code.toLowerCase().includes(t) || c.name.toLowerCase().includes(t));
  }, [g.apiGroup, g.searchTerm]);

  return (
    <>
      <tr className={`${styles.tr} ${isResolved ? styles.trResolved : styles.trPending}`}>
        {/* # */}
        <td className={styles.td} style={{ color: '#9ca3af', fontSize: 11 }}>{idx}</td>

        {/* Đối tác */}
        <td className={styles.td}>
          <div className={styles.partnerName} title={g.counterpartyName}>
            {g.counterpartyName || <em style={{ color: '#9ca3af' }}>Không tên</em>}
          </div>
          {g.bankAccountCode && (
            <div className={styles.partnerAcct}>{g.bankAccountCode}</div>
          )}
        </td>

        {/* Dòng */}
        <td className={styles.td} style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums', color: '#374151' }}>
          {g.rowCount}
        </td>

        {/* Trạng thái */}
        <td className={styles.td}>
          <span className={styles.badge} style={{ background: statusBg, color: statusFg }}>
            {statusText}
          </span>
        </td>

        {/* Đối tượng / Định khoản */}
        <td className={styles.td}>
          {g.isExpenseKind ? (
            /* Chi phí: show posting category dropdown */
            <div className={styles.expenseRow}>
              <span className={styles.expenseCatLabel}>{g.postingCategoryLabel}</span>
              <select
                className={styles.postingSelect}
                value={g.postingCode || ''}
                onChange={e => onUpdate({ postingCode: e.target.value })}
              >
                <option value="">-- Chọn định khoản --</option>
                {POSTING_OPTS.map(o => (
                  <option key={o.code} value={o.code}>{o.label}</option>
                ))}
              </select>
            </div>
          ) : g.selectedId ? (
            /* Auto or manual matched */
            <div className={styles.matchedCell}>
              <span className={styles.matchedCode}>
                {g.apiGroup?.exactMatch?.code || g.selectedId}
              </span>
              <span className={styles.matchedName}>
                {g.apiGroup?.exactMatch?.name}
              </span>
              {g.apiGroup?.exactMatch?.matchScore && (
                <span className={styles.matchScore}>{g.apiGroup.exactMatch.matchScore}%</span>
              )}
            </div>
          ) : g.createNew ? (
            /* Create new */
            <span className={styles.createNewChip}>
              + Tạo: <strong>{g.newCustomerName || g.counterpartyName}</strong>
            </span>
          ) : (
            /* Pending → show lookup if open */
            <span className={styles.pendingHint}>— chưa chọn —</span>
          )}
        </td>

        {/* Hành động */}
        <td className={styles.td}>
          <div className={styles.actionCell}>
            {!g.skip && (
              <button
                className={styles.actionBtn}
                onClick={() => onUpdate({ showLookup: !g.showLookup, searchTerm: '' })}
              >
                {g.selectedId || g.createNew ? 'Đổi' : 'Chọn'}
              </button>
            )}
            <button
              className={`${styles.actionBtn} ${styles.actionBtnGray}`}
              onClick={() => onUpdate({ skip: !g.skip, showLookup: false })}
            >
              {g.skip ? 'Khôi phục' : 'Bỏ qua'}
            </button>
          </div>
        </td>
      </tr>

      {/* Inline lookup panel */}
      {g.showLookup && !g.skip && !g.isExpenseKind && (
        <tr className={styles.lookupRow}>
          <td />
          <td colSpan={5} className={styles.lookupCell}>
            <div className={styles.lookupPanel}>
              <input
                className={styles.lookupSearch}
                placeholder="Tìm mã hoặc tên đối tượng..."
                value={g.searchTerm}
                autoFocus
                onChange={e => onUpdate({ searchTerm: e.target.value })}
              />
              {cands.length > 0 ? (
                <div className={styles.candidateList}>
                  {cands.slice(0, 6).map(c => (
                    <button
                      key={c.customerId}
                      className={`${styles.candidateItem} ${g.selectedId === c.customerId ? styles.candidateItemActive : ''}`}
                      onClick={() => onUpdate({ selectedId: c.customerId, showLookup: false, createNew: false })}
                    >
                      <span className={styles.cCode}>{c.code}</span>
                      <span className={styles.cName}>{c.name}</span>
                      <span className={styles.cScore} style={{
                        color: c.matchScore >= 90 ? '#16a34a' : c.matchScore >= 70 ? '#ca8a04' : '#dc2626',
                      }}>{c.matchScore}%</span>
                    </button>
                  ))}
                </div>
              ) : (
                <p className={styles.noCandidate}>Không tìm thấy đối tượng phù hợp.</p>
              )}
              <button className={styles.createNewBtn} onClick={onCreateNew}>
                + Tạo mới đối tượng
              </button>
            </div>
          </td>
        </tr>
      )}
    </>
  );
};

// ── CreateCustomerModal ───────────────────────────────────────

interface CreateModalProps {
  group: MGroup;
  onConfirm: (name: string) => void;
  onClose: () => void;
}

const CreateCustomerModal: React.FC<CreateModalProps> = ({ group, onConfirm, onClose }) => {
  const [name, setName] = useState(group.newCustomerName || group.counterpartyName);

  return (
    <div className={styles.modalOverlay} onClick={onClose}>
      <div className={styles.modalContent} onClick={e => e.stopPropagation()}>
        <div className={styles.modalHeader}>
          <h4>Tạo đối tượng mới</h4>
          <button className={styles.modalClose} onClick={onClose}>×</button>
        </div>
        <div className={styles.modalBody}>
          <p style={{ marginBottom: 12, fontSize: 13, color: '#6b7280' }}>
            Mã sẽ được tự động tạo. Bạn có thể chỉnh sửa thêm trong danh mục Đối tượng sau khi import.
          </p>
          <label className={styles.fieldLabel}>Tên đối tượng</label>
          <input
            className={styles.fieldInput}
            value={name}
            onChange={e => setName(e.target.value)}
            autoFocus
          />
          {group.bankAccountCode && (
            <p style={{ fontSize: 12, color: '#9ca3af', marginTop: 6 }}>
              TK NH: {group.bankAccountCode}
            </p>
          )}
          <p style={{ fontSize: 12, color: '#6b7280', marginTop: 8 }}>
            Áp dụng cho <strong>{group.rowCount}</strong> dòng của đối tác này.
          </p>
        </div>
        <div className={styles.modalActions}>
          <button className={styles.modalCancelBtn} onClick={onClose}>Huỷ</button>
          <button
            className={styles.modalConfirmBtn}
            disabled={!name.trim()}
            onClick={() => onConfirm(name.trim())}
          >
            Tạo đối tượng
          </button>
        </div>
      </div>
    </div>
  );
};

export default CustomerGroupMatch;
