/** Danh sách đã sắp xếp theo priority giảm dần (bỏ fallback). */
const SORTED_CATEGORIES = [...POSTING_CATEGORIES]
  .filter(c => c.code !== 'CHUA_PHAN_LOAI')
  .sort((a, b) => (b.priority ?? 0) - (a.priority ?? 0));

const FALLBACK_CATEGORY = POSTING_CATEGORIES.find(c => c.code === 'CHUA_PHAN_LOAI')!;

/**
 * Phát hiện loại định khoản từ nội dung chuyển khoản + tên đối tác.
 * Trả CHUA_PHAN_LOAI nếu không khớp.
 */
export function detectPostingCategory(
  description: string,
  counterparty?: string,
): PostingCategoryEntry {
  const normDesc = normPostingText(description ?? '');
  const normCp = normPostingText(counterparty ?? '');

  for (const cat of SORTED_CATEGORIES) {
    const allKw = [...(cat.keywords ?? []), ...(cat.descriptionOnlyKeywords ?? [])];
    if (allKw.some(re => re.test(normDesc))) return cat;
    if (cat.supplierKeywords && normCp) {
      if (cat.supplierKeywords.some(re => re.test(normCp))) return cat;
    }
  }

  return FALLBACK_CATEGORY;
}

